#!/usr/bin/env bash
# bridge-v2.sh — standalone Bridge page + ETH->LCAI wallet fix + official labeling
# Run from the filament repo root AFTER add-bridge.sh (v1) was applied.
set -euo pipefail
[ -f config/bridge.ts ] || { echo "v1 not applied — run add-bridge.sh first"; exit 1; }

base64 -d > config/bridge.ts <<'B64EOF'

B64EOF

base64 -d > contracts/warpRouteAbi.ts <<'B64EOF'

B64EOF

base64 -d > components/bridge/bridge-form.tsx <<'B64EOF'

B64EOF

base64 -d > app/bridge/page.tsx <<'B64EOF'

B64EOF

base64 -d > components/swap-pools-tabs.tsx <<'B64EOF'

B64EOF

python3 - <<'EOF'
# Header: add Bridge to main nav
p='components/header/Header.tsx'; s=open(p).read()
old='''const NAV = [
  { href: "/", label: "Exchange" },
  { href: "/forge", label: "Forge" },
  { href: "/markets", label: "Markets" },
  { href: "/portfolio", label: "Portfolio" },
];'''
new='''import { BRIDGE_ENABLED } from "@/config/bridge";

const NAV = [
  { href: "/", label: "Exchange" },
  { href: "/forge", label: "Forge" },
  ...(BRIDGE_ENABLED ? [{ href: "/bridge", label: "Bridge" }] : []),
  { href: "/markets", label: "Markets" },
  { href: "/portfolio", label: "Portfolio" },
];'''
if 'href: "/bridge"' not in s:
    assert old in s, "Header NAV anchor not found"
    s=s.replace(old,new); open(p,'w').write(s)

# Mobile menu
p='components/header/MobileMenu.tsx'; s=open(p).read()
old='  { href: "/pools", label: "Pools", sub: "Earn from liquidity" },'
new='''  { href: "/pools", label: "Pools", sub: "Earn from liquidity" },
  { href: "/bridge", label: "Bridge", sub: "Official LCAI bridge" },'''
if '/bridge' not in s:
    assert old in s, "MobileMenu anchor not found"
    s=s.replace(old,new); open(p,'w').write(s)

# AppKit must know about Ethereum or chain-switching fails (the ETH->LCAI bug)
p='context/index.tsx'; s=open(p).read()
if 'networks: config.chains,' in s:
    s=s.replace('networks: config.chains,','networks,')
    s=s.replace('import config from "@/config";',
                'import config from "@/config";\nimport { networks } from "@/config/wagmi";')
    open(p,'w').write(s)
print("v2 patches applied")
EOF

npx tsc --noEmit && echo "BRIDGE V2 READY — typecheck clean"
